DOMAIN_SUMMARY = 'Real estate operations frequently deal with incidents requiring escalation, such as critical maintenance failures, tenant disputes, lease violations, or vendor issues. Timely and accurate triage is crucial to mitigate risks, ensure tenant satisfaction, and maintain property value. This project aims to centralize internal knowledge documents (e.g., escalation matrices, policy manuals) and provide an AI assistant to guide operations staff on appropriate actions and urgency levels for various incidents.'
USER_PERSONA = 'Property Manager Assistant or Junior Operations Coordinator: A new or entry-level team member who needs quick, reliable information on how to handle specific real estate operational escalations, understand company policies, and determine appropriate next steps without extensive senior oversight or manual policy lookup.'
STARTER_QUESTIONS = ['How do I escalate a critical water leak affecting multiple units?', 'What is the procedure for handling a repeated noise complaint against a tenant?', "A vendor invoice is overdue by 60 days, what's the next step?", 'What forms are needed to initiate an eviction process for lease violation?', 'What are the emergency contact protocols for a major power outage in a property?']
WORKFLOW_STEPS = ['1. Setup Environment: User installs Docker, Ollama, and project dependencies.', '2. Start Services: User runs `docker compose up` to start backend, frontend, and Ollama.', '3. Access UI: User navigates to `localhost:3000` (or configured frontend port).', "4. Document Ingestion: User uploads relevant policy documents (e.g., PDF of 'Escalation Matrix v3.1', 'Tenant Handbook 2024', 'Vendor Payment Policy').", '5. Indexing: Backend processes documents: parses text, generates embeddings, and stores them in ChromaDB.', "6. User Query: User types a question into the chat interface (e.g., 'What's the process for a major HVAC breakdown?').", '7. Retrieval: Backend receives query, generates embedding, performs a similarity search in ChromaDB to find top-k relevant document chunks.', "8. LLM Interaction: Backend constructs a prompt with the user's query and the retrieved document context, sends it to the local Ollama LLM."]
BUSINESS_RULES = ['Maximum document size for upload is 10MB.', 'Only PDF and TXT file types are accepted for document ingestion.', 'If the RAG system cannot find sufficiently relevant information (similarity score below a threshold) for a user query, the LLM should clearly state that it lacks information on the topic and suggest uploading more relevant documents.', "LLM responses should be concise and actionable, focusing on the 'next steps' or 'who to contact' where applicable, as per the persona's needs.", "Automatically identify and highlight keywords related to 'escalation level' (e.g., Critical, Urgent, Standard) in the LLM's response if inferred from the retrieved context.", 'All document processing (embedding generation) should occur asynchronously to not block the UI during uploads.']
TOOL_CATALOG = [{'name': 'retrieval_tool', 'description': "Retrieves relevant document chunks from the vector database based on a semantic search of the user's query. Provides contextual information for the LLM."}]
